const express = require('express');
const bodyParser = require('body-parser');
const { exec } = require('child_process');
const axios = require('axios');

const app = express();
app.use(bodyParser.json());

const AI_MODEL_URL = 'https://api.your-llm-provider.com/generate'; // Replace with your LLM API URL
const AI_API_KEY = 'your_api_key'; // Replace with your API key

app.post('/generate-code', async (req, res) => {
    const { description } = req.body;

    try {
        const aiResponse = await axios.post(AI_MODEL_URL, {
            prompt: `Generate safe and executable JavaScript code for the following task: ${description}`,
            max_tokens: 150,
        }, {
            headers: {
                'Authorization': `Bearer ${AI_API_KEY}`,
                'Content-Type': 'application/json',
            },
        });

        const generatedCode = aiResponse.data.choices[0].text.trim();

        // Simple validation to prevent execution of harmful code
        if (isSafeCode(generatedCode)) {
            exec(generatedCode, (error, stdout, stderr) => {
                if (error) {
                    return res.status(500).json({ error: stderr });
                }
                res.json({ output: stdout });
            });
        } else {
            res.status(400).json({ error: 'Generated code is not safe to execute.' });
        }
    } catch (error) {
        res.status(500).json({ error: 'Error communicating with AI model.' });
    }
});

function isSafeCode(code) {
    const forbiddenPatterns = [
        /process\.env/,
        /require\(/,
        /fs\./,
        /child_process\./,
        /exec\(/,
        /eval\(/,
        /Function\(/,
    ];
    return !forbiddenPatterns.some(pattern => pattern.test(code));
}

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
    console.log(`Server is running on port ${PORT}`);
});